```java
@Service
public class OrderService {
    private final OrderRepository orderRepository;
    private final PaymentGateway paymentGateway;
    private final InventoryClient inventoryClient;

    public OrderService(OrderRepository orderRepository, PaymentGateway paymentGateway, InventoryClient inventoryClient) {
        this.orderRepository = orderRepository;
        this.paymentGateway = paymentGateway;
        this.inventoryClient = inventoryClient;
    }

    public Order placeOrder(Long customerId, List<OrderItem> items) {
        for (OrderItem item : items) {
            if (!inventoryClient.checkAvailability(item.getSku(), item.getQuantity())) {
                throw new InsufficientInventoryException("Not enough stock for SKU: " + item.getSku());
            }
        }
        double total = items.stream().mapToDouble(i -> i.getPrice() * i.getQuantity()).sum();
        PaymentResult payment = paymentGateway.charge(customerId, total);
        if (!payment.isSuccess()) {
            throw new PaymentFailedException("Payment failed: " + payment.getErrorMessage());
        }
        Order order = new Order(customerId, items, total);
        return orderRepository.save(order);
    }

    public Order getOrder(Long orderId) {
        return orderRepository.findById(orderId)
            .orElseThrow(() -> new OrderNotFoundException("Order not found: " + orderId));
    }

    public void cancelOrder(Long orderId) {
        Order order = orderRepository.findById(orderId)
            .orElseThrow(() -> new OrderNotFoundException("Order not found: " + orderId));
        if (order.isShipped()) {
            throw new IllegalStateException("Cannot cancel shipped order");
        }
        order.setStatus(OrderStatus.CANCELLED);
        orderRepository.save(order);
        paymentGateway.refund(customerId, order.getTotal());
    }
}
